src/main.ts<pre><code>import { App, Stack } from '@cdk-x/core';
import { HtzLoadBalancer, HtzLoadBalancerService, LoadBalancerType, LoadBalancerServiceProtocol, NetworkZone } from '@cdk-x/hetzner';

const app = new App();
const stack = new Stack(app, 'LbStack');

const lb = new HtzLoadBalancer(stack, 'LoadBalancer', {
  name: 'my-lb',
  loadBalancerType: LoadBalancerType.LB11,
  networkZone: NetworkZone.EU_CENTRAL,
});

new HtzLoadBalancerService(stack, 'HttpService', {
  loadBalancerId: lb.attrLoadBalancerId, // (1)!
  listenPort: 80,
  protocol: LoadBalancerServiceProtocol.TCP,
  destinationPort: 8080, // (2)!
  proxyprotocol: false,
});

app.synth();
</code></pre> <ol> <li><code>attrLoadBalancerId</code> resolves to the integer load balancer ID. The service is created after the load balancer.</li> <li>Frontend listens on port 80, forwards to port 8080 on the backend.</li> </ol>

src/main.ts<pre><code>import { App, Stack } from '@cdk-x/core';
import { HtzLoadBalancer, HtzServer, HtzLoadBalancerTarget, LoadBalancerType, LoadBalancerTargetType, NetworkZone, ServerType } from '@cdk-x/hetzner';

