</code></pre>

.cdkxrc.ts<pre><code>import { Workspace, YamlFile } from '@cdk-x/core';
import { MltInstance, MltNetwork, MltConfig } from '@cdk-x/multipass';

const workspace = new Workspace();
const multipass = new YamlFile(workspace, 'DevVMs', { fileName: 'multipass.yaml' });

const bridge = new MltNetwork(multipass, 'Bridge', {
  name: 'bridge',
  mode: 'auto',
});

const dev = new MltInstance(multipass, 'Dev', {
  name: 'dev',
  image: 'jammy',
  networks: [bridge.ref], // (1)!
});

new MltConfig(multipass, 'Config', { instances: [dev.ref] });

workspace.synth();
</code></pre> <ol> <li>Pass <code>bridge.ref</code> — not the object itself. The ref resolves at synthesis and nests the network config inside the instance YAML entry.</li> </ol> <p>Produces:</p> <pre><code>instances:
  - name: dev
    image: jammy
    networks:
      - name: bridge
        mode: auto
</code></pre>
